package com.example.pc4_luisfelipecanalalvarado.data

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import androidx.sqlite.db.SupportSQLiteDatabase

@Database(
    entities = [Airport::class, Favorite::class],
    version = 1,
    exportSchema = false
)
abstract class FlightSearchDatabase : RoomDatabase() {

    abstract fun airportDao(): AirportDao
    abstract fun favoriteDao(): FavoriteDao

    companion object {
        @Volatile
        private var Instance: FlightSearchDatabase? = null

        fun getDatabase(context: Context): FlightSearchDatabase {
            return Instance ?: synchronized(this) {
                Room.databaseBuilder(
                    context.applicationContext,
                    FlightSearchDatabase::class.java,
                    "flight_search.db"
                )
                    .fallbackToDestructiveMigration()
                    .addCallback(object : RoomDatabase.Callback() {
                        override fun onCreate(db: SupportSQLiteDatabase) {
                            super.onCreate(db)
                            // Populate initial data
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (1, 'LIM', 'Jorge Chavez International Airport', 18000000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (2, 'CUZ', 'Alejandro Velasco Astete International Airport', 2000000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (3, 'AQP', 'Rodriguez Ballon International Airport', 1500000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (4, 'TRU', 'Capitan FAP Carlos Martinez de Pinillos International Airport', 1200000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (5, 'PIU', 'Capitan FAP Guillermo Concha Iberico International Airport', 800000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (6, 'JFK', 'John F. Kennedy International Airport', 60000000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (7, 'LAX', 'Los Angeles International Airport', 82000000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (8, 'MIA', 'Miami International Airport', 42000000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (9, 'MAD', 'Adolfo Suarez Madrid-Barajas Airport', 57000000)")
                            db.execSQL("INSERT INTO airport(id, iata_code, name, passengers) VALUES (10, 'BOG', 'El Dorado International Airport', 32000000)")
                        }
                    })
                    .build()
                    .also { Instance = it }
            }
        }
    }
}

package com.example.pc4_luisfelipecanalalvarado.data

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase

@Database(
    entities = [Airport::class, Favorite::class],
    version = 1,
    exportSchema = false
)
abstract class FlightSearchDatabase : RoomDatabase() {

    abstract fun airportDao(): AirportDao
    abstract fun favoriteDao(): FavoriteDao

    companion object {
        @Volatile
        private var Instance: FlightSearchDatabase? = null

        fun getDatabase(context: Context): FlightSearchDatabase {
            return Instance ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    FlightSearchDatabase::class.java,
                    "flight_search.db"
                ).fallbackToDestructiveMigration().build()
                Instance = instance
                instance
            }
        }
    }
}
